// Como cada conceito aparece no projeto:

// INTERFACES → modelam entidades
interface Aluno { nome: string; nota: number; }

// ARRAYS → agrupam coleções
const turma: Aluno[] = [{ nome: "Ana", nota: 9 }];

// FUNÇÕES → encapsulam ações
function media(notas: number[]): number {
  let soma: number = 0;
  for (const n of notas) soma += n;
  return soma / notas.length;
}

// O padrão de "loop até condição" aparece em muitos contextos
// Caixa de banco:
let senhaAtual: number = 1;
const totalSenhas: number = 5;

while (senhaAtual <= totalSenhas) {
  console.log(`Atendendo senha ${senhaAtual}`);
  senhaAtual++;
}
console.log("Todas as senhas atendidas!");

// Decomposição: problema grande → partes pequenas
// Em vez de resolver tudo de uma vez:

// Parte 1: definir os dados
interface Produto { nome: string; preco: number; }

// Parte 2: criar função de processamento
function calcularTotal(produtos: Produto[]): number {
  let total: number = 0;
  for (const p of produtos) total += p.preco;
  return total;
}

// Parte 3: juntar tudo
const carrinho: Produto[] = [{ nome: "Livro", preco: 40 }];
console.log(`Total: R$${calcularTotal(carrinho)}`);
// Total: R$40

// Planejamento antes de codar
// Passo 1: Que dados preciso? → interfaces
// Passo 2: Como organizo? → objetos e arrays
// Passo 3: Que ações existem? → funções
// Passo 4: O que se repete? → loops
// Passo 5: Que decisões tomar? → condicionais

// Exemplo: sistema de notas
interface Prova { materia: string; nota: number; }

const provas: Prova[] = [
  { materia: "Matemática", nota: 8 },
  { materia: "Português", nota: 7 }
];

for (const p of provas) {
  const status: string = p.nota >= 6 ? "Aprovado" : "Recuperação";
  console.log(`${p.materia}: ${status}`);
}

// Combinando condicionais com loops — padrão do combate
const estoque: number[] = [10, 0, 5, 0, 8];

for (const qtd of estoque) {
  if (qtd > 0) {
    console.log(`Em estoque: ${qtd} unidades`);
  } else {
    console.log("Esgotado!");
  }
}
// Em estoque: 10 unidades
// Esgotado!
// Em estoque: 5 unidades
// Esgotado!
// Em estoque: 8 unidades

// Funções que modificam objetos — base do sistema de combate
interface ContaBancaria {
  titular: string;
  saldo: number;
}

function depositar(conta: ContaBancaria, valor: number): void {
  conta.saldo += valor;
  console.log(`Depósito de R$${valor}. Saldo: R$${conta.saldo}`);
}

const minhaConta: ContaBancaria = { titular: "Ana", saldo: 100 };
depositar(minhaConta, 50);
depositar(minhaConta, 30);
// Depósito de R$50. Saldo: R$150
// Depósito de R$30. Saldo: R$180

// Modelando com interface — padrão do exercício
interface Veiculo {
  marca: string;
  modelo: string;
  ano: number;
  km: number;
}

const carro: Veiculo = {
  marca: "Fiat",
  modelo: "Uno",
  ano: 2020,
  km: 35000
};

console.log(`${carro.marca} ${carro.modelo} (${carro.ano})`);
// Fiat Uno (2020)

// Arrays de objetos — mesma estrutura do inventário
interface Ingrediente {
  nome: string;
  quantidade: number;
  unidade: string;
}

const receita: Ingrediente[] = [
  { nome: "Farinha", quantidade: 500, unidade: "g" },
  { nome: "Ovos", quantidade: 3, unidade: "un" },
  { nome: "Leite", quantidade: 200, unidade: "ml" }
];

console.log(`Ingredientes: ${receita.length}`);
// Ingredientes: 3

// .toUpperCase() para formatação
const nome: string = "Maria Silva";

console.log(nome);
console.log(nome.toUpperCase());
console.log(nome.toLowerCase());
// Maria Silva
// MARIA SILVA
// maria silva

// Formato com separadores (pipe) — como na saída do exercício
const aluno = {
  nome: "Lucas",
  nota: 8,
  turma: "7A",
  frequencia: 95
};

console.log(`=== ${aluno.nome.toUpperCase()} ===`);
console.log(`Nota: ${aluno.nota} | Turma: ${aluno.turma} | Freq: ${aluno.frequencia}%`);
// === LUCAS ===
// Nota: 8 | Turma: 7A | Freq: 95%

// Várias interfaces no mesmo programa
interface Escola {
  nome: string;
  cidade: string;
}

interface Professor {
  nome: string;
  materia: string;
}

const escola: Escola = { nome: "Colégio Central", cidade: "Curitiba" };
const professores: Professor[] = [
  { nome: "Ana", materia: "Matemática" },
  { nome: "Bruno", materia: "Português" }
];

console.log(`${escola.nome} — ${escola.cidade}`);
console.log(`Professores: ${professores.length}`);
// Colégio Central — Curitiba
// Professores: 2

// .length conta os itens do array
const tarefas: string[] = ["Estudar", "Exercitar", "Ler"];
const compras: string[] = ["Arroz", "Feijão"];

console.log(`Tarefas: ${tarefas.length} itens`);
console.log(`Compras: ${compras.length} itens`);
// Tarefas: 3 itens
// Compras: 2 itens

// Função que modifica propriedade de um objeto
interface Conta {
  titular: string;
  saldo: number;
}

function sacar(conta: Conta, valor: number): void {
  conta.saldo -= valor;
  console.log(`${conta.titular} sacou R$${valor}. Saldo: R$${conta.saldo}`);
}

const minhaConta: Conta = { titular: "Ana", saldo: 500 };
sacar(minhaConta, 100);
sacar(minhaConta, 200);
// Ana sacou R$100. Saldo: R$400
// Ana sacou R$200. Saldo: R$200

// Math.max garante um valor mínimo
console.log(Math.max(1, 5));
console.log(Math.max(1, -3));
console.log(Math.max(1, 0));
// 5 — 5 é maior que 1
// 1 — -3 é menor que 1, então usa 1
// 1 — 0 é menor que 1, então usa 1

// Loop while com condição composta
let energiaA: number = 100;
let energiaB: number = 80;

while (energiaA > 0 && energiaB > 0) {
  energiaB -= 35;
  if (energiaB <= 0) {
    console.log("B ficou sem energia!");
    break;
  }
  energiaA -= 25;
  console.log(`A: ${energiaA} | B: ${energiaB}`);
}
// A: 75 | B: 45
// A: 50 | B: 10
// B ficou sem energia!

// Simulando as contas do combate Aria vs Slime
// Slime: HP 30, Ataque 8
// Aria: HP 100, Ataque 20, Defesa 5

const danoHeroi: number = 20 - 2;
const danoMonstro: number = Math.max(1, 8 - 5);

console.log(`Dano do herói: ${danoHeroi}`);
console.log(`Dano do monstro: ${danoMonstro}`);

// Turno 1: Slime HP: 30 - 18 = 12 (vive), Aria HP: 100 - 3 = 97
// Turno 2: Slime HP: 12 - 18 = -6 (morre antes de atacar)
console.log("Turno 1: Slime sobrevive, contra-ataca");
console.log("Turno 2: Slime derrotado");

// break encerra o loop imediatamente
const alvos: number[] = [10, 20, 30, 40, 50];

for (const alvo of alvos) {
  if (alvo === 30) {
    console.log(`Encontrou: ${alvo}`);
    break;
  }
  console.log(`Checando ${alvo}...`);
}
// Checando 10...
// Checando 20...
// Encontrou: 30

// Funções que trabalham juntas — mesmo padrão do combate
interface Estoque {
  produto: string;
  quantidade: number;
}

function vender(e: Estoque, qtd: number): void {
  e.quantidade -= qtd;
  console.log(`Vendeu ${qtd} ${e.produto}. Restam: ${e.quantidade}`);
}

function mostrar(e: Estoque): void {
  console.log(`[${e.produto}] Estoque: ${e.quantidade}`);
}

const item: Estoque = { produto: "Caderno", quantidade: 50 };
vender(item, 10);
mostrar(item);
// Vendeu 10 Caderno. Restam: 40
// [Caderno] Estoque: 40

// Revisão: variáveis e tipos
let nome: string = "Programador";
let nivel: number = 1;
let pronto: boolean = true;

console.log(`${nome} nível ${nivel}`);
// Programador nível 1

// Revisão: condicionais
const nota: number = 8;

if (nota >= 9) {
  console.log("Excelente!");
} else if (nota >= 7) {
  console.log("Muito bom!");
} else {
  console.log("Continue praticando!");
}
// Muito bom!

// Revisão: loops
for (let i: number = 5; i >= 1; i--) {
  console.log(`${i}...`);
}
console.log("Lançar!");
// 5... 4... 3... 2... 1... Lançar!

// Revisão: funções
function saudar(nome: string, hora: number): string {
  if (hora < 12) return `Bom dia, ${nome}!`;
  if (hora < 18) return `Boa tarde, ${nome}!`;
  return `Boa noite, ${nome}!`;
}

console.log(saudar("Ana", 9));
console.log(saudar("Bruno", 15));
// Bom dia, Ana!
// Boa tarde, Bruno!

// Revisão: arrays + map/filter
const notas: number[] = [8, 5, 9, 3, 7, 6];

const aprovados: number[] = notas.filter((n: number): boolean => n >= 6);
const dobradas: number[] = aprovados.map((n: number): number => n * 2);

console.log(aprovados);
console.log(dobradas);
// [8, 9, 7, 6]
// [16, 18, 14, 12]

// Revisão: objetos e interfaces
interface Conquista {
  titulo: string;
  descricao: string;
  desbloqueada: boolean;
}

const conquistas: Conquista[] = [
  { titulo: "Primeiro Código", descricao: "Escreveu a primeira variável", desbloqueada: true },
  { titulo: "Mestre dos Loops", descricao: "Completou todos os exercícios de loops", desbloqueada: true },
  { titulo: "Programador Completo", descricao: "Finalizou o CodeQuest", desbloqueada: true }
];

for (const c of conquistas) {
  console.log(`🏆 ${c.titulo}`);
}
// 🏆 Primeiro Código
// 🏆 Mestre dos Loops
// 🏆 Programador Completo
